
.visual-card {
    width: 150px;
    height: 220px;
    perspective: 1000px;
    cursor: pointer;
    margin: 10px;

    .card-inner {
        position: relative;
        width: 100%;
        height: 100%;
        text-align: center;
        transition: transform 0.6s;
        transform-style: preserve-3d;
    }

    &.flipped .card-inner {
        transform: rotateY(180deg);
    }

    .card-front,
    .card-back {
        position: absolute;
        width: 100%;
        height: 100%;
        -webkit-backface-visibility: hidden;
        backface-visibility: hidden;
        border-radius: 10px;
        box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
        overflow: hidden;
        display: flex;
        flex-direction: column;
        justify-content: center;
        align-items: center;
    }

    .card-front {
        background-color: #fff;

        .card-image {
            width: 100%;
            height: 100%;
            object-fit: cover;
        }

        .card-name {
            position: absolute;
            bottom: 0;
            width: 100%;
            background: rgba(0, 0, 0, 0.5);
            color: white;
            padding: 5px 0;
            font-size: 14px;
        }
    }

    .card-back {
        background-color: #f8f9fa;
        color: #333;
        transform: rotateY(180deg);
        padding: 15px;

        .back-content {
            display: flex;
            align-items: center;
            justify-content: center;
            height: 100%;
        }

        .back-text {
            font-size: 14px;
            line-height: 1.4;
        }
    }
}
